49	function isValidDomain($domain)
50	{
51	  // Remove any leading or trailing whitespace
52	  $domain = trim($domain);
53	
54	  // Define the regular expression pattern for domain validation
55	  $pattern = '/^(?!:\/\/)(?:[-A-Za-z0-9]+\.)+[A-Za-z]{2,6}$/';
56	
57	  // Perform the regular expression match
58	  return preg_match($pattern, $domain) === 1;
59	}
