69	function refferDomain($url)
70	{
71	  $parsedUrl = parse_url($url);
72	  $host = isset($parsedUrl['host']) ? $parsedUrl['host'] : '';
73	  $hostParts = explode('.', $host);
74	
75	  // Extract domain name
76	  if (count($hostParts) > 2) {
77	    $domain = $hostParts[count($hostParts) - 2] . '.' . $hostParts[count($hostParts) - 1];
78	  } else {
79	    $domain = $host;
80	  }
81	
82	  return $domain; // Outputs: example.com
83	}
