203	function email($data)
204	{
205	  if (get_settings('global_email')) {
206	    if (get_settings('email_type') == 'php') {
207	      $headers = "From: " . get_settings('name_from') . " <" . get_settings('email_from') . "> \r\n";
208	      $headers .= "Reply-To: get_settings('name_from') <" . get_settings('email_from') . "> \r\n";
209	      $headers .= "MIME-Version: 1.0\r\n";
210	      $headers .= "Content-Type: text/html; charset=utf-8\r\n";
211	      @mail($data['email'], $data['subject'], $data['message'], $headers);
212	    } else {
213	      $mail = new PHPMailer(true);
214	
215	      try {
216	        $mail->isSMTP();
217	        $mail->Host       = get_settings('smtp_host');
218	        $mail->SMTPAuth   = true;
219	        $mail->Username   = get_settings('smtp_user');
220	        $mail->Password   = get_settings('smtp_pass');
221	        if (get_settings('smtp_encryption') == 'ssl') {
222	          $mail->SMTPSecure = PHPMailer::ENCRYPTION_SMTPS;
223	        } else {
224	          $mail->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
225	        }
226	        $mail->Port    = get_settings('smtp_port');
227	        $mail->CharSet = 'UTF-8';
228	        $mail->setFrom(get_settings('email_from'), get_settings('name_from'));
229	        $mail->addAddress($data['email'], $data['name']);
230	        $mail->addReplyTo(get_settings('email_from'), get_settings('name_from'));
231	        $mail->isHTML(true);
232	        $mail->Subject = $data['subject'];
233	        $mail->Body    = $data['message'];
234	        $mail->send();
235	      } catch (Exception $e) {
236	        throw new Exception($e);
237	      }
238	    }
239	  }
240	}
